import { createStore, type StoreApi } from 'zustand';

import { parserVersion } from '../utils/conversion/tree-conversion.js';

/** @internal */
export interface StoredFilter {
  filter: string;
  parserVersion: string;
  timeUsed: Date;
}

/**
 * Interface defining the store for recent filters.
 * @internal
 */
export interface RecentAndPinnedFiltersState {
  canPin: boolean;
  setCanPin: (canPin: boolean) => void;
  recentFilters: Array<StoredFilter>;
  setRecentFilters: (filters: Array<StoredFilter>) => void;
  saveRecentFilter: (filter: string) => Array<StoredFilter>;
  pinnedFilters: Array<StoredFilter>;
  setPinnedFilters: (filters: Array<StoredFilter>) => void;
  pinFilter: (filter: string) => Array<StoredFilter>;
  unpinFilter: (filter: string) => Array<StoredFilter>;
}

/**
 * Update logic for saving a filter to the store.
 * @internal
 */
export function addFilterToState(
  storedFilters: StoredFilter[],
  filter: string,
  limit: number,
): StoredFilter[] {
  const trimmedFilter = filter.trim();
  const foundIndex = storedFilters.findIndex(
    (saved) => saved.filter === trimmedFilter,
  );
  const newValues = [...storedFilters];

  // The current filter that is trying to be saved was not in the store yet
  // so we can add it.
  if (foundIndex === -1) {
    newValues.push({
      filter: trimmedFilter,
      parserVersion: parserVersion,
      timeUsed: new Date(),
    });
  } else if (foundIndex > -1) {
    // If the filter is found in the list, but the parser version
    // mismatches, we can update the parser version.
    if (storedFilters[foundIndex].parserVersion !== parserVersion) {
      newValues[foundIndex].parserVersion = parserVersion;
    }

    // If the filter is found in the list, we can also update the timeUsed
    storedFilters[foundIndex].timeUsed = new Date();
  }

  // Sort by timeUsed descending (newest first).
  newValues.sort((a, b) => b.timeUsed.getTime() - a.timeUsed.getTime());

  return newValues.slice(0, limit);
}

/**
 * Update logic for unpinning a filter
 * @internal
 */
export function removeFilterFromState(
  storedFilters: StoredFilter[],
  filter: string,
): StoredFilter[] {
  const trimmedFilter = filter.trim();
  const foundIndex = storedFilters.findIndex(
    (saved) => saved.filter === trimmedFilter,
  );
  const newValues = [...storedFilters];

  if (foundIndex > -1) {
    newValues.splice(foundIndex, 1);
  }
  return newValues;
}

/**
 * Creates a standalone store that can be used to namespace connected filter field storages.
 * @internal
 */
export function createRecentAndPinnedFilterStore() {
  return createStore<RecentAndPinnedFiltersState>((set, get) => ({
    canPin: true,
    setCanPin: (canPin: boolean) => {
      set(() => ({ canPin }));
    },
    recentFilters: [],
    setRecentFilters: (filters: StoredFilter[]) => {
      set(() => ({ recentFilters: filters }));
    },
    saveRecentFilter: (filterString: string) => {
      set((state) => ({
        recentFilters: addFilterToState(state.recentFilters, filterString, 100),
      }));
      return get().recentFilters;
    },
    pinnedFilters: [],
    setPinnedFilters: (filters: StoredFilter[]) => {
      set(() => ({ pinnedFilters: filters }));
    },
    pinFilter: (filterString: string) => {
      set((state) => ({
        pinnedFilters: addFilterToState(state.pinnedFilters, filterString, 10),
      }));
      return get().pinnedFilters;
    },
    unpinFilter: (filterString: string) => {
      set((state) => ({
        pinnedFilters: removeFilterFromState(state.pinnedFilters, filterString),
      }));
      return get().pinnedFilters;
    },
  }));
}

/**
 * Void store for opt out feature
 * @internal
 */
export const voidStore = createStore<RecentAndPinnedFiltersState>(() => ({
  canPin: true,
  setCanPin: () => undefined,
  recentFilters: [],
  setRecentFilters: () => undefined,
  saveRecentFilter: (filter: string) => [],
  pinnedFilters: [],
  setPinnedFilters: (filters: StoredFilter[]) => undefined,
  pinFilter: (filter: string) => [],
  unpinFilter: (filter: string) => [],
}));

/**
 * Create a shareable saved filters store map that maps a namespace to a store.
 * @internal
 */
export const scopedRecentAndPinnedFiltersStores = new Map<
  string | symbol,
  StoreApi<RecentAndPinnedFiltersState>
>([['root', createRecentAndPinnedFilterStore()]]);
